import type { CodegenConfig } from '@graphql-codegen/cli'

const codegenCommentPlugin = () => ({
    add: {
        content: [
            '// This file is autogenerated by @graphql-codegen/cli',
            '// Do not edit / add anything manually, since it will be overridden by codegen',
        ],
    },
})

const exportFromPlugin = (from: string) => {
    return {
        add: {
            content: `export * from '${from}'`,
        },
    }
}

const config: CodegenConfig = {
    overwrite: true,
    schema: 'schema.graphql',
    documents: 'domains/**/queries/*.graphql',
    generates: {
        'schema.ts': {
            plugins: [
                codegenCommentPlugin(),
                'typescript',
            ],
        },
        'gql/operation.types.ts': {
            preset: 'import-types',
            presetConfig: {
                typesPath: '@app/~/schema',
            },
            plugins: [
                codegenCommentPlugin(),
                'typescript-operations',
            ],
        },
        'gql/index.ts': {
            preset: 'import-types',
            presetConfig: {
                typesPath: '@app/~/gql/operation.types',
            },
            plugins: [
                codegenCommentPlugin(),
                'typescript-react-apollo',
                exportFromPlugin('@app/~/gql/operation.types'),
            ],
        },
    },
}

export default config
